document.addEventListener("nav",()=>{document.querySelectorAll(".leaflet-map-container").forEach(t=>{let o=Number(t.dataset.zoom??13),s=Number(t.dataset.lat??0),l=Number(t.dataset.lng??0),d=t.dataset.tileUrl??"https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png",n=JSON.parse(t.dataset.markers??"[]"),a=L.map(t).setView([s,l],o);L.tileLayer(d,{attribution:"\xA9 OpenStreetMap contributors"}).addTo(a),n.forEach(e=>{L.marker([e.lat,e.lng]).addTo(a).bindPopup(`
          <div class="leaflet-popup-inner">
            <strong>${e.title??""}</strong>
            ${e.description?`<p>${e.description}</p>`:""}
          </div>
        `)}),window.addCleanup(()=>a.remove())})});
